+ 
+ int
+ next()
+ {
+ 	int trk;
+ 	struct ioc_toc_header h;
+ 	int rc, n;
+ 
+ 	rc = ioctl(fd, CDIOREADTOCHEADER, &h);
+ 
+ 	if (rc < 0)
+ 		return (rc);
+ 
+ 	n = h.ending_track - h.starting_track + 1;
+ 
+ 	if (status(&trk, &rc, &rc, &rc) < 0)
+ 		return (-1);
+ 
+ 	if (++trk > h.ending_track)
+ 		trk = 1;
+ 	return play_track(trk, 1, n, 1);
+ }
+ 
+ int
+ previous()
+ {
+ 	int trk;
+ 	struct ioc_toc_header h;
+ 	int rc, n;
+ 
+ 	rc = ioctl(fd, CDIOREADTOCHEADER, &h);
+ 
+ 	if (rc < 0)
+ 		return (rc);
+ 
+ 	n = h.ending_track - h.starting_track + 1;
+ 
+ 	if (status(&trk, &rc, &rc, &rc) < 0)
+ 		return (-1);
+ 
+ 	if (--trk < 1)
+ 		trk = h.ending_track;
+ 	return play_track(trk, 1, n, 1);
  }
